def themed_block(now: datetime) -> str:
    title, pool = THEMES[now.weekday()]
    # deterministic pick per calendar day → same content if workflow is run twice
    seed = int(now.strftime("%Y%m%d"))
    item = random.Random(seed).choice(pool)

    if isinstance(item, tuple):
        head, body = item
        return f"<b>{title} — {head.upper()}</b>\n\n{body}"
    return f"<b>{title}</b>\n\n{item}"


def compose(now: datetime) -> str:
    diff = TARGET - now
    days = diff.days

    if now.date() == TARGET.date():
        return ("🎉 <b>СЕГОДНЯ.</b>\n"
                "Турция, мы идём. Паспорта, билеты, шлёпки — три раза проверили? Точно?\n\n"
                f"{SITE}")

    if now.date() > TARGET.date():
        gone = (now.date() - TARGET.date()).days
        return f"🐚 Отпуск идёт уже {gone} {days_word(gone)}. Кто-то забыл выключить этот воркфлоу. Это нормально."

    seed = int(now.strftime("%Y%m%d"))
    rnd = random.Random(seed + 1)
    header = rnd.choice(COUNTDOWN_HEADERS).format(d=days, w=days_word(days))
    body = themed_block(now)
    return f"{header}\n\n{body}"


def send(text: str) -> None:
    token = os.environ["TG_BOT_TOKEN"]
    chat = os.environ["TG_CHAT_ID"]
    url = f"https://api.telegram.org/bot{token}/sendMessage"
    data = urllib.parse.urlencode({
        "chat_id": chat,
        "parse_mode": "HTML",
        "disable_web_page_preview": "true",
        "text": text,
    }).encode()
    req = urllib.request.Request(url, data=data)
    with urllib.request.urlopen(req, timeout=15) as r:
        resp = json.loads(r.read())
    print(json.dumps(resp, ensure_ascii=False, indent=2))
    if not resp.get("ok"):
        raise SystemExit(1)


if __name__ == "__main__":
    now = datetime.now(MSK)
    msg = compose(now)
    print("--- message ---")
    print(msg)
    print("---------------")
    send(msg)
